class Solution {
    public int minimumDeleteSum(String s1, String s2) {
        int[] charMap = new int[26];
        for (int i = 0; i < s1.length(); i++) {
            charMap[s1.charAt(i)]++;
        }
        for (int i = 0; i < s2.length(); i++) {
            charMap[s2.charAt(i)]--;
        }
        int sum = 0;
        for (int i = 0; i < 26; i++) {
            sum += charMap[i] * (charMap[i] + 1);
        }
        return sum;
    }
}
```

